vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    vec2 uv_echo = (vUv - 0.5)*1.010*vec2(-1,-1) + 0.5;
    ret = abs( texture(sampler_main, vUv).xyz -
                    texture(sampler_main, uv_echo).zyx );
vec4 noise2 = texture3D(sampler_noisevol_hq,
                      ((uv_echo.xyy
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*0.4
                     );
if(ret.x+ret.y+ret.z>.5)ret -= (noise2)*.5;

  fragColor = ret;
}
